import{_ as m,o as h,c as _,a6 as c,gn as d,go as F,gp as T,gq as N,gr as u,es as f,gs as b,gt as k,gu as x,gv as K,gw as P,gh as S,gx as C,gy as p,gz as V,gA as A,gB as v,gC as D,gD as w,gE as B,gF as o,gG as s,gH as i,gI as I,gJ as g,gK as y,gL as n,gM as R,gN as E,gO as H,gP as O,gQ as Q,gR as $,gS as j,gT as l,gU as q,gV as G,gW as J,gX as M,gY as X,gZ as z,ey as L,g_ as U,g$ as W,h0 as Y,h1 as Z,h2 as pp,h3 as sp,h4 as tp,he as rp,hf as ap,hg as op,hh as ip,hi as gp,hj as np,hk as lp,hc as ep,hl as mp,hd as hp,hm as _p,hb as cp,hs as dp,ht as Fp,hu as Tp,hv as Np,hw as up,hx as fp,hy as bp,hz as kp,hD as xp,hE as Kp,hF as Pp,hG as Sp,hH as Cp,hI as Vp,hJ as Ap,hK as vp,hL as t,hM as Dp,hN as wp,hO as e,hP as r,hQ as Bp,hR as Ip,hS as yp,hT as Rp,hU as Ep}from"./chunks/framework.UYVGz2W_.js";const Mp=JSON.parse('{"title":"NFTコレクションを作成する","description":"","frontmatter":{},"headers":[],"relativePath":"ja/nft/index.md","filePath":"ja/nft/index.md"}'),Hp={name:"ja/nft/index.md"};function Op(Qp,a,$p,jp,qp,Gp){return h(),_("div",null,[...a[0]||(a[0]=[c('<h1 id="nftコレクションを作成する" tabindex="-1">NFTコレクションを作成する <a class="header-anchor" href="#nftコレクションを作成する" aria-label="Permalink to “NFTコレクションを作成する”">​</a></h1><p>Kitsuでワークフローを設計し、より多くの人を招待したので、今度は作品を作成する番です。</p><p><strong>新しい作品を作成</strong>ボタンをクリックします。</p><p><img src="'+d+'" alt="作品を作成"></p><p>制作物の名前を入力し、<strong>タイプ</strong>として<strong>短い</strong>を選択し、制作スタイル（2D、3D）を選択します。</p><p>次に、FPS数、アスペクト比、解像度などの技術情報を入力します。</p><p>これらのデータはすべて、Kitsuがアップロードされたビデオプレビューを再エンコードする際に使用されます。</p><p>次に、制作物の開始日と終了日を定義する必要があります。</p><p><img src="'+F+'" alt="プロダクションの追加"></p><p>プロダクションのワークフローは、次のパート3から6で定義できます。</p><p>アセットタスクタイプ（3）、NFTコレクションタスクタイプ（4）、タスクステータス（5）、アセットタイプ（6）を選択する必要があります。</p><p><img src="'+T+'" alt="Add a production Pipeline"></p><p>::: ヒント <strong>プロダクションワークフロー</strong>を作成するには、グローバルライブラリからタスクタイプを選択します。</p><p>タスクタイプをいくつか見落としていたことに気づいた場合は、後で作成できます。</p><p>「スタジオワークフロー」（../configure-kitsu/index.md#studio-workflow）セクションを参照してください。 :::</p><p>次に、7と8はオプション部分です。アセット/NFTコレクションの一覧が記載されたスプレッドシートがすでに用意されている場合。</p><p>詳細は「<strong>CSVのインポート</strong>」セクションを参照してください。</p><p>アセットのインポート</p><p>NFTコレクションのインポート</p><p><img src="'+N+'" alt="All done">ボタンですべてを確認します。</p><h2 id="kitsuグローバルページの紹介" tabindex="-1">Kitsuグローバルページの紹介 <a class="header-anchor" href="#kitsuグローバルページの紹介" aria-label="Permalink to “Kitsuグローバルページの紹介”">​</a></h2><p>Kitsuのグローバルアセットページへようこそ。</p><p>見てみましょう。</p><p><img src="'+u+'" alt="グローバルページの紹介"></p><p>上部 (1) には、<strong>グローバルナビゲーション</strong>があり、これはすべての制作ページで常に表示されます。</p><p><strong>左から右へ:</strong></p><h3 id="メインメニュー" tabindex="-1">メインメニュー <a class="header-anchor" href="#メインメニュー" aria-label="Permalink to “メインメニュー”">​</a></h3><p>左上のボタン、Kitsu<img src="'+f+'" alt="メインメニューボタン">（またはお客様のスタジオロゴ）をクリックすると、メインメニューが開きます。</p><p>メインメニューでは、割り当てられたタスク、制作物、グローバルおよびチームスケジュール、ワークフローのカスタマイズページ、およびKitsu設定に直接アクセスできます。</p><p>::: 詳細 メインメニューの詳細 <strong>ワークスペース</strong></p><ul><li>マイタスク：割り当てられたタスク</li><li>マイチェック：あなたの部署に応じて、ステータスが<strong>フィードバックリクエスト</strong>となっているすべてのタスク</li><li>マイプロダクション：プロダクションページの選択に戻ります。</li></ul><p><strong>スタジオ</strong></p><ul><li>プロダクション</li><li>担当者</li><li>タイムシート</li><li>メインスケジュール</li><li>チームスケジュール</li><li>すべてのタスク</li><li>ニュースフィード</li><li>エンティティ検索</li></ul><p><strong>ADMIN</strong></p><ul><li>部署</li><li>タスクの種類</li><li>アセットの種類</li><li>カスタムアクション</li><li>自動化</li><li>3D背景</li><li>ボット</li><li>設定</li><li>ログ</li></ul><p>::: 警告 権限の表示 ワークスペースセクションは、アーティストには表示されない「マイチェック」を除くすべての権限に対して有効になっています。</p><p>アーティスト（およびそれ以上）は、自身の<strong>タイムシート</strong>も表示でき、<strong>エンティティ検索</strong>にもアクセスできます :::</p><h3 id="ナビゲーション" tabindex="-1">ナビゲーション <a class="header-anchor" href="#ナビゲーション" aria-label="Permalink to “ナビゲーション”">​</a></h3><p>メインメニューアイコンの右側にナビゲーションドロップダウンメニューが表示されます。</p><p><img src="'+b+'" alt="グローバルページの表示"></p><p>制作を選択できます。実際の制作名と実際のページ名が常に表示されます。</p><p>ドロップダウンメニューを使用して、制作から制作へと移動できます（複数の制作がある場合）。</p><p>制作を選択すると、次のドロップダウンメニューで、その制作の異なるページを移動することができます。</p><p>::: 詳細 ナビゲーション詳細 最初のセクションは、タスクのトラッキングについてです</p><ul><li>資産</li><li>NFTコレクション</li><li>シーケンス</li><li>編集（特定のタスクを作成した場合）</li></ul><p>2番目のセクションは、制作の側面についてです</p><ul><li>コンセプト</li><li>ブレークダウン</li><li>プレイリスト</li><li>ニュースフィード</li></ul><p>3番目のセクションは統計情報です</p><ul><li>シーケンス統計</li><li>アセットタイプ統計</li></ul><p>4番目のセクションはチーム管理に関連しています</p><ul><li>スケジュール</li><li>ノルマ</li><li>チーム</li></ul><p>5番目のセクションは制作の設定です</p><ul><li>設定</li></ul><p>::: ヒント アセットページから開始しますが、制作のホームページを他のエンティティに変更することができます（設定ページを参照）。 :::</p><p>::: 警告 エピソードなど、追加のナビゲーションレベルが必要になった場合は、プロダクションタイプを<strong>テレビ番組</strong>に変更する必要があります。</p><p>逆に、<strong>アセット</strong>や<strong>NFTコレクション</strong>が必要ない場合は、プロダクションタイプを<strong>アセットのみ</strong>または<strong>NFTコレクションのみ</strong>に切り替える必要があります。 :::</p><h3 id="グローバル検索、ニュース、通知、およびドキュメント" tabindex="-1">グローバル検索、ニュース、通知、およびドキュメント <a class="header-anchor" href="#グローバル検索、ニュース、通知、およびドキュメント" aria-label="Permalink to “グローバル検索、ニュース、通知、およびドキュメント”">​</a></h3><p>グローバル検索はナビゲーションドロップダウンメニューの右側にあります。 4件の最初の結果を表示するクイックアクセス検索です。 さらに多くの結果やフィルタリングオプションが必要な場合は、<strong>エンティティ検索</strong>ページを参照してください。</p><p>次のアイコン <img src="'+k+'" alt="ニュース"> は、ニュースとフィードバックページへの直接リンクです。</p><p>アニメーションGIFで新機能のすべてをご覧いただけます。また、Kitsuに追加してほしい次期機能に関するご意見もご投稿いただけます。</p><p>ベルのアイコンは、通知（割り当て、コメント、タグ）を表示します！<a href="../img/getting-started/notification_icon_on.png">通知</a>。未読通知の数はベルのアイコンに表示されます。</p><p>アバターの直前のアイコンは、ドキュメントボタンです。 <img src="'+x+'" alt="ドキュメントボタン"> あなたが今読んでいるドキュメントです！</p><h3 id="個人設定" tabindex="-1">個人設定 <a class="header-anchor" href="#個人設定" aria-label="Permalink to “個人設定”">​</a></h3><p>アバターをクリックすると、メニュー（設定、ドキュメントなど）を開くことができます。</p><p><img src="'+K+'" alt="プロフィール拡大"></p><h2 id="タスクスプレッドシート" tabindex="-1">タスクスプレッドシート <a class="header-anchor" href="#タスクスプレッドシート" aria-label="Permalink to “タスクスプレッドシート”">​</a></h2><h3 id="エンティティスプレッドシート" tabindex="-1">エンティティスプレッドシート <a class="header-anchor" href="#エンティティスプレッドシート" aria-label="Permalink to “エンティティスプレッドシート”">​</a></h3><p>画面の2番目の部分は、すべてのエンティティ（アセット、NFTコレクション、シーケンス、編集）に共通です。これはグローバルなタスクスプレッドシートです。</p><p>ここでは、各タスクのステータス、割り当て、優先度などを確認できます。</p><p>::: ヒント スプレッドシートの最初の行と列のヘッダーは、スクロールしても常にページの上部に表示されます。</p><p>また、他の列を常に表示しておくために「固定」することもできます。 :::</p><h3 id="フィルター" tabindex="-1">フィルター <a class="header-anchor" href="#フィルター" aria-label="Permalink to “フィルター”">​</a></h3><p>左側の最初の要素はフィルターボックスです。単純なフィルタリング、順序、アセットタイプなど、任意の文字列を入力することができます。</p><p>より高度なフィルタリングが必要な場合は、フィルタービルダーボタンを使用してください。</p><p><img src="'+P+'" alt="フィルタービルダー"></p><p>すべてのフィルターを保存し、ページとして使用することができます。</p><h3 id="表示の簡素化" tabindex="-1">表示の簡素化 <a class="header-anchor" href="#表示の簡素化" aria-label="Permalink to “表示の簡素化”">​</a></h3><p>画面の右側には、左から右に、アサインメントの表示/非表示、追加カラムの表示/非表示、サムネイルの拡大/縮小を行うためのボタンがあります。 <img src="'+S+'" alt="表示と非表示オプション"></p><h3 id="インポート-エクスポート" tabindex="-1">インポート / エクスポート <a class="header-anchor" href="#インポート-エクスポート" aria-label="Permalink to “インポート / エクスポート”">​</a></h3><p>バッチインポートサムネイル <img src="'+C+'" alt="バッチインポートサムネイル">、最後にインポート <img src="'+p+'" alt="インポートボタン"> またはエクスポート <img src="'+V+'" alt="エクスポートボタン"> データの</p><h3 id="メタデータカラム" tabindex="-1">メタデータカラム <a class="header-anchor" href="#メタデータカラム" aria-label="Permalink to “メタデータカラム”">​</a></h3><p>以下に、カラムの名前があります。「名前」の隣にある(+)をクリックしてください！<a href="../img/getting-started/add_column_custom.png">メタデータカラムの追加</a>をクリックすると、新しいメタデータカラムを作成できます。次に、タスクタイプのカラムの名前があります。</p><h3 id="ビューのカスタマイズ" tabindex="-1">ビューのカスタマイズ <a class="header-anchor" href="#ビューのカスタマイズ" aria-label="Permalink to “ビューのカスタマイズ”">​</a></h3><p>画面の一番右側にあるスクロールバーの隣に、テキストカラムの非表示/表示オプションがあります</p><p><img src="'+A+'" alt="テキストカラムの表示/非表示">。</p><h3 id="ビューの要約" tabindex="-1">ビューの要約 <a class="header-anchor" href="#ビューの要約" aria-label="Permalink to “ビューの要約”">​</a></h3><p>画面の一番下の最後の部分（4）は、表示されているページの要約です。つまり、ページをフィルタリングすると要約が更新されます。</p><p>要素（アセットまたはNFTコレクション）の数、見積もり日数の合計、およびすでに費やした日数の合計を確認できます。</p><h2 id="アセットの作成" tabindex="-1">アセットの作成 <a class="header-anchor" href="#アセットの作成" aria-label="Permalink to “アセットの作成”">​</a></h2><h3 id="最初の資産の作成" tabindex="-1">最初の資産の作成 <a class="header-anchor" href="#最初の資産の作成" aria-label="Permalink to “最初の資産の作成”">​</a></h3><p>さて、プロダクションを作成し、Kitsuインターフェースの概要を理解したので、最初の資産を作成してみましょう。</p><p>アセットページで、<strong>[アセットを追加]</strong>をクリックします。</p><p><img src="'+v+'" alt="アセットページ初回"></p><p>::: 警告 アセットを作成すると、タスクワークフローが適用され、<strong>すべてのタスクがアセットと同時に作成されます</strong>。 :::</p><p>ポップアップウィンドウが開きます。</p><p><strong>アセットタイプ</strong>を選択するよう求められます（1）。 新しいアセットタイプを追加していない場合、Kitsuは「キャラクター」、「環境」、「エフェクト」、「小道具」などの例を提供します。 キャラクターから始めましょう。</p><p>次に<strong>名前</strong>を入力し (2)、アーティストが何をすべきか、またアセットを素早く識別できるように説明を入力します。</p><p>複数のアセットを作成する場合は、<strong>[Confirm and stay]</strong>をクリックします。</p><p><img src="'+D+'" alt="アセットの作成"></p><p>アセットの種類を変更して、アセットを追加し続けることができます。</p><p>::: ヒント 「確認して戻る」をクリックするたびに、新しく作成されたアセットが背景に表示されます。 :::</p><p>最後のアセットを追加したら、 「確認」をクリックします。アセットが作成され、ウィンドウが閉じます。</p><p>ヒント 「確認してそのままにする」をクリックし、追加するアセットがないことに気づいたら、「閉じる」をクリックすると、ウィンドウがキャンセルされます。 ヒント</p><p><img src="'+w+'" alt="グローバルアセットページ"></p><p>アセットワークフローで選択されたタスクも同時に作成されます。</p><p>さらに<strong>アセット</strong>を追加する必要がある場合は、<strong>+ Create assets</strong>（アセットの作成）ボタンをクリックします。</p><p>::: 詳細 CSVスプレッドシートファイルからアセットを作成 アセットのリストがすでにスプレッドシートファイルに用意されている場合もあります。 Kitsuでは、インポートする方法が2つあります。1つ目は、<code>.csv</code>ファイルをインポートし、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、スプレッドシートを<code>.csv</code>ファイルとして保存します。</p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします。 <img src="'+p+'" alt="インポートアイコン"></p><p>ポップアップウィンドウの<strong>「CSVからデータをインポート」</strong>が開きます。<strong>「参照」</strong>をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+B+'" alt="インポートcsvファイル"></p><p>結果を確認するには、<strong>[プレビュー]</strong>ボタンをクリックします。</p><p>データのプレビューで、列の名前を確認し、調整することができます。</p><p>注：<strong>[エピソード]</strong>列は、<strong>[テレビ番組]</strong>制作の場合のみ必須です。</p><p><img src="'+o+'" alt="データのコピー＆ペースト"></p><p>すべてが適切であることを確認したら、<strong>[確認]</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべての資産がKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+s+'" alt="インポートデータコピーペーストデータ"> ::::</p><p>:::: 詳細 スプレッドシートファイルのコピー/ペーストによる資産の作成</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+i+'" alt="コピーデータのインポート"></p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ<strong>CSVからのインポート</strong>が開きますので、<strong>CSVデータの貼り付け</strong>タブをクリックします。</p><p><img src="'+I+'" alt="インポートデータのコピー＆ペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong>ボタンで結果を確認できます。</p><p><img src="'+g+'" alt="インポートデータのコピー＆ペーストデータ"></p><p>データのプレビューで列の名前を確認し、調整することができます。</p><p>注意：<strong>エピソード</strong>の列は、<strong>テレビ番組</strong>の制作の場合のみ必須です。</p><p><img src="'+o+'" alt="インポートデータ コピーペーストデータ"></p><p>すべて問題なければ、<strong>確認</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+s+'" alt="インポートデータ コピーペーストデータ"> :::</p><h3 id="アセットの詳細を確認する" tabindex="-1">アセットの詳細を確認する <a class="header-anchor" href="#アセットの詳細を確認する" aria-label="Permalink to “アセットの詳細を確認する”">​</a></h3><p>アセットの詳細を確認するには、その名前をクリックします。</p><p><img src="'+y+'" alt="アセットの詳細"></p><p>新しいページが開き、右側にタスク、アサイン、ステータスニュースフィードの一覧が表示されます。</p><p><img src="'+n+'" alt="アセット詳細ページ"></p><p>各タスクのステータスをクリックすると、コメントパネルが開き、コメントの履歴や異なるバージョンを確認できます。</p><p><img src="'+R+'" alt="アセット詳細ページ"></p><p>また、<strong>キャスティング</strong>にもアクセスできます。</p><p><img src="'+E+'" alt="アセット詳細キャスティング"></p><p>このアセットに関連付けられた<strong>コンセプト</strong>にもアクセスできます。</p><p><img src="'+H+'" alt="アセット詳細キャスティング"></p><p><strong>スケジュール</strong>は、タスクタイプページのデータを事前に記入していれば利用できます。データがすでに記入されている場合は、ここで直接修正することができます。</p><p><img src="'+O+'" alt="アセット詳細キャスティング"></p><p>さまざまなタスクタイプでアップロードされた<strong>プレビューファイル</strong>、</p><p><img src="'+Q+'" alt="アセット詳細のキャスティング"></p><p>そして、このアセットのタスクでタイムシートが記入された場合の<strong>タイムログ</strong>。</p><p><img src="'+$+'" alt="アセット詳細のキャスティング"></p><h2 id="アセットを作成した後にタスクを追加する" tabindex="-1">アセットを作成した後にタスクを追加する <a class="header-anchor" href="#アセットを作成した後にタスクを追加する" aria-label="Permalink to “アセットを作成した後にタスクを追加する”">​</a></h2><p>アセットを作成した後にタスクが欠けていることに気づいた場合でも、追加することができます。</p><p>まず、欠けているタスクタイプがタスクタイプタブの設定ページに追加されていることを確認してください。</p><p>次に、アセットページに戻り、<strong>+ タスクを追加</strong>をクリックします</p><h3 id="アセットを更新する" tabindex="-1">アセットを更新する <a class="header-anchor" href="#アセットを更新する" aria-label="Permalink to “アセットを更新する”">​</a></h3><p>アセットはいつでも更新でき、名前やアセットタイプを変更したり、説明文を修正したり、グローバルページに追加したカスタム情報を追加したりすることができます。</p><p>アセットを編集するには、アセットページに移動し、編集したいアセットの上にカーソルを移動させて、<strong>編集</strong>ボタンをクリックします ！<a href="../img/getting-started/edit_button.png">編集ボタン</a> (1) 行の右側にある</p><p><img src="'+j+'" alt="アセットの編集"></p><p>アセットのメインページの説明を拡張するには、最初の語句 (2) をクリックすると、説明の全文を含むポップアップが開きます。</p><p>アセットを削除するには、FAQ : アセットの削除方法を参照してください。</p><p>::: 詳細 CSV インポートによるアセットの更新 CSV インポートを使用すると、データを素早く更新することができます。</p><p>アセットの<strong>タイプ</strong>、<strong>アサイン</strong>、タスクの<strong>ステータス</strong>を更新したり、<strong>コメント</strong>を追加したりすることができます。</p><p><strong>既存のデータを更新する</strong>オプションをオンにする必要があります。すると、更新される行が 青くハイライトされます。</p><p><img src="'+l+'" alt="インポートデータ コピー＆ペーストデータ"></p><p>:::</p><p>::: 詳細 スプレッドシートファイルのコピー＆ペーストによるアセットの更新</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+i+'" alt="インポート コピーデータ"></p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします ！<a href="../img/getting-started/import.png">インポートアイコン</a>。</p><p>ポップアップウィンドウ「<strong>CSVからデータをインポート</strong>」が開きます。「<strong>CSVデータを貼り付け</strong>」タブをクリックします。</p><p>！<a href="../img/getting-started/import_pastcsvdata_asset.png">インポートデータコピーペーストタブ</a></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong> ボタンで結果を確認できます。</p><p><img src="'+g+'" alt="データのコピー＆ペースト"></p><p>データをプレビューして、列の名前を確認し、調整することができます。</p><p>注：<strong>[エピソード]</strong> 列は、<strong>[テレビ番組]</strong> 制作の場合のみ必須です。</p><p>オプション「<strong>既存データの更新</strong>」をオンにする必要があります。すると、更新される行が 青くハイライトされます。</p><p><img src="'+l+'" alt="データのインポート データのコピー＆ペースト"></p><p>これで、すべてのアセットがKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+s+'" alt="インポートデータ コピーペーストデータ"> :::</p><h2 id="コンセプトの作成" tabindex="-1">コンセプトの作成 <a class="header-anchor" href="#コンセプトの作成" aria-label="Permalink to “コンセプトの作成”">​</a></h2><h3 id="コンセプトのアップロード" tabindex="-1">コンセプトのアップロード <a class="header-anchor" href="#コンセプトのアップロード" aria-label="Permalink to “コンセプトのアップロード”">​</a></h3><p><strong>コンセプト</strong>を作成するには、ナビゲーションメニューから<strong>コンセプト</strong>ページに移動します。</p><p><img src="'+q+'" alt="コンセプトメニュー"></p><p>コンセプトをアップロードするには、「<strong>コンセプトへの新しい参照を追加</strong>」ボタンをクリックします。</p><p>同時に1つまたは複数のコンセプトをアップロードできます。</p><p><img src="'+G+'" alt="コンセプトの空ページ"></p><p>プレビューをアップロードすると、コンセプトページは次のようになります。</p><p><img src="'+J+'" alt="コンセプトの入力ページ"></p><p>コンセプトとやりとりするには2つの方法があります。画像をクリックして拡大表示します。 もう1つは、ステータス部分をクリックして右側の<strong>コメントパネル</strong>を開く方法です。</p><p>コメントパネルでは、コンセプトを既存のアセットにリンクするか、削除するかの2つのオプションがあります。 また、アセットにコメントを追加したり、ステータスを変更することもできます。</p><p><strong>コンセプト</strong>ごとに1つのバージョンを持つことが基本です。 検証されていない場合は、同じコンセプトの複数のバージョンを作成しないよう、新しいコンセプトをアップロードする必要があります。</p><p>1つのコンセプトは1つのタスクです。</p><p><img src="'+M+'" alt="コンセプトオプション"></p><h3 id="コンセプトとアセットのリンク" tabindex="-1">コンセプトとアセットのリンク <a class="header-anchor" href="#コンセプトとアセットのリンク" aria-label="Permalink to “コンセプトとアセットのリンク”">​</a></h3><p>コンセプトをアップロードすると、アセットにリンクすることができます。</p><p>アセットのステータス部分にリンクが表示されます。</p><p>コンセプトのステータス部分をクリックすると、右側にコメントパネルが開きます。</p><p><img src="'+X+'" alt="コンセプトコメントパネル"></p><p>コメントパネルの上部には、コンセプトをアセットにリンクするか、コンセプトを削除するかの2つのオプションがあります。</p><p>アセットをリンクするには、[リンク] ボタン <img src="'+z+'" alt="リンクボタン"> をクリックします。</p><p>Kitsu は、アップロードしたコンセプトにリンク可能なすべての <strong>アセット</strong> を表示します。</p><p>Kitsu は、リンクされたアセットをコメントパネルの上部にリスト表示します。現時点では、リンクはありません。</p><p><img src="'+L+'" alt="コンセプトリンク"></p><p>アセットをリンクするには、それをクリックします。リンクされたアセットの名前は、コンセプトのプレビューの下に画面の上部に表示されます。</p><p><img src="'+U+'" alt="コンセプトアセットリンク"></p><p>コンセプトがアセットにリンクされると、アセットの詳細ページで確認できます。</p><p>アセットページに戻り、コンセプトを確認したいアセット名をクリックします。</p><p><img src="'+n+'" alt="アセット詳細ページ"></p><p>デフォルトでは、キャスティングの詳細が画面の2番目の部分に表示されます。 ドロップダウンメニューを使用してコンセプトを選択します。</p><p><img src="'+W+'" alt="アセット詳細コンセプト"></p><p>コンセプトセクションに入ると、このアセット用に作成されたすべてのコンセプトが表示されます。ステータスごとにフィルタリングできます。</p><p><img src="'+Y+'" alt="アセット詳細コンセプトリスト"></p><h2 id="nftコレクションの作成" tabindex="-1">NFTコレクションの作成 <a class="header-anchor" href="#nftコレクションの作成" aria-label="Permalink to “NFTコレクションの作成”">​</a></h2><h3 id="最初のnftコレクションの作成" tabindex="-1">最初のNFTコレクションの作成 <a class="header-anchor" href="#最初のnftコレクションの作成" aria-label="Permalink to “最初のNFTコレクションの作成”">​</a></h3><p>制作した<strong>NFTコレクション</strong>を作成する時が来ました。</p><p>::: 警告 NFTコレクションは、Kitsu内のシーケンスにリンクされています。 シーケンスを作成し、その中にNFTコレクションを追加する必要があります。 :::</p><p>NFTコレクション<strong>ページに移動する必要があります。 ドロップダウンメニューを使用して、</strong>NFTコレクション**をクリックします。</p><p><img src="'+Z+'" alt="ドロップダウンメニューNFTコレクション"></p><p><strong>NFTコレクションの追加</strong>ボタンをクリックして、NFTコレクションの作成を開始します。</p><p><img src="'+pp+'" alt="まずNFTコレクションを追加"></p><p>::: 警告 NFTコレクションを作成すると、設計したタスクワークフローが適用され、すべてのタスクがNFTコレクションと同時に作成されます。 :::</p><p>NFTコレクションの作成用に新しいポップアップが開きます。 これでシーケンスとNFTコレクションを作成できます。</p><p>最初のシーケンス、例えば「sq01」を入力し、 次に<strong>追加</strong>します。</p><p>これで、シーケンスが作成されたことが確認できます。このシーケンスにNFTコレクションを追加するには、シーケンスを選択してNFTコレクションを作成する必要があります。</p><p>例えば、NFTコレクションの列に「sh0010」と入力し、再度<strong>追加</strong>します。 NFTコレクションのパディングを定義することもできます。</p><p>::: ヒント NFTコレクションを10個ごとにSH0010、SH0020、SH0030などと名付けたい場合は、<strong>NFTコレクションのパディング</strong>を10に設定します :::</p><p><img src="'+sp+'" alt="NFTコレクションの管理"></p><p>新しいNFTコレクションが、シーケンス順にリスト化され、リンクされているのが確認できます。 これで、最初のシーケンスの最初のNFTコレクションが作成されました。</p><p>それでは、NFTコレクションを1つ以上追加してみましょう！ご覧の通り、ボックスにはすでに名前のコードが含まれていますが、 コードが含まれていますが、インクリメントされているので、<strong>追加</strong>をクリックして さらにNFTコレクションを作成する必要があります。</p><p><img src="'+tp+'" alt="NFTコレクションの追加"></p><p>さらにシーケンスを追加するには、左側部分に移動し、新しいシーケンスの名前を入力し、<strong>追加</strong>をクリックします。 2番目のシーケンスが選択され、NFTコレクションを追加できるようになります。</p><p>::: ヒント NFTコレクションがシーケンス上で誤った場所に配置されている場合は、NFTコレクションを編集する必要があります ！<a href="../img/getting-started/edit_button.png">編集ボタン</a>をクリックし、 シーケンスを変更します。 ！<a href="../img/getting-started/edit_shot.png">NFTコレクションの編集 シーケンスの変更</a></p><p>！<a href="../img/getting-started/change_seq.png">シーケンスの変更</a> :::</p><p>NFTコレクションを削除するには、FAQを参照してください。 : NFTコレクションの削除方法</p><p>シーケンスを削除するには、FAQを参照してください。 : シーケンスの削除方法</p><h3 id="nftコレクションの詳細を確認する" tabindex="-1">NFTコレクションの詳細を確認する <a class="header-anchor" href="#nftコレクションの詳細を確認する" aria-label="Permalink to “NFTコレクションの詳細を確認する”">​</a></h3><p>NFTコレクションの詳細を確認したい場合は、その名前をクリックします。</p><p><img src="'+rp+'" alt="NFTコレクションの詳細"></p><p>新しいページが開き、右側にタスク、アサインメント、ステータスニュースフィードの一覧が表示されます。 タブの名前をクリックすることで、それぞれを移動できます。</p><p><img src="'+ap+'" alt="NFTコレクション詳細ページ"></p><p>各タスクのステータスをクリックすると、コメントパネルが開き、コメントの履歴や異なるバージョンを確認できます。</p><p><img src="'+op+'" alt="NFTコレクション詳細ページ"></p><p>また、<strong>キャスティング</strong>にもアクセスできます。</p><p><img src="'+ip+'" alt="アセット詳細キャスティング"></p><p><strong>スケジュール</strong>は、事前にタスクタイプページのデータを入力している場合に利用できます。データがすでに記入されている場合は、ここで直接修正することができます。</p><p><img src="'+gp+'" alt="アセット詳細キャスティング"></p><p>さまざまなタスクタイプでアップロードされた<strong>プレビューファイル</strong>、</p><p><img src="'+np+'" alt="アセット詳細キャスティング"></p><p>そして、このアセットのタスクでタイムシートが記入された場合の<strong>タイムログ</strong>。</p><p><img src="'+lp+'" alt="アセット詳細キャスティング"></p><h2 id="nftコレクションを作成した後にタスクを追加する" tabindex="-1">NFTコレクションを作成した後にタスクを追加する <a class="header-anchor" href="#nftコレクションを作成した後にタスクを追加する" aria-label="Permalink to “NFTコレクションを作成した後にタスクを追加する”">​</a></h2><p>NFTコレクションを作成した後にタスクが不足していることに気づいた場合でも、追加することができます。</p><p>まず、不足しているタスクタイプがタスクタイプタブの設定ページに追加されていることを確認します。</p><p>次に、NFTコレクションページに移動し、「+タスクを追加」をクリックします。</p><h3 id="nftコレクションを更新する" tabindex="-1">NFTコレクションを更新する <a class="header-anchor" href="#nftコレクションを更新する" aria-label="Permalink to “NFTコレクションを更新する”">​</a></h3><p>いつでもNFTコレクションを更新し、名前や順序を変更したり、説明文やグローバルページに追加したカスタム情報を修正することができます。</p><p>NFTコレクションを編集するには、NFTコレクションページに移動し、変更したいNFTコレクションにカーソルを合わせて、行の右側にある<strong>編集</strong>ボタンをクリックします 右側の行にある[編集]ボタン (1) をクリックします。</p><p>アセットの編集] (../img/getting-started/asset_edit01.png)</p><p>NFTコレクションのメインページの説明を拡張するには、最初の文字 (2) をクリックすると、説明の全文を含むポップアップが開きます。</p><p>::: 詳細 NFTコレクション情報のCSVインポートによる更新 CSVインポート<strong>を使用して、</strong>NBフレーム<strong>、</strong>フレームIN<strong>、</strong>フレームアウト<strong>、または任意のカスタム</strong>メタデータ列**としてデータを更新することができます。</p><p>タスクの<strong>割り当て</strong>と<strong>ステータス</strong>を更新し、<strong>コメント</strong>を追加することができます。</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+ep+'" alt="インポートコピーデータ"></p><p>次に、KitsuのNFTコレクションページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ<strong>インポートデータからCSV</strong>が開きます。<strong>CSVデータを貼り付け</strong>タブをクリックします。</p><p><img src="'+mp+'" alt="インポートデータのコピー＆ペーストタブ"></p><p>以前に選択したデータをペーストし、<strong>[プレビュー]</strong>ボタンで結果を確認できます。</p><p><img src="'+hp+'" alt="インポートデータのコピー＆ペーストデータ"></p><p>オプション：既存のデータを更新** をオンにする必要があります。 更新されたNFTコレクションは青くなります</p><p>注：<strong>エピソード</strong>の列は、<strong>TV Show</strong>制作の場合のみ必須です。</p><p><img src="'+_p+'" alt="Import data copy paste data"></p><p>すべて問題なければ、<strong>Confirm</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、NFTコレクションがすべてKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+cp+'" alt="インポートデータコピーペーストデータ"> :::</p><h2 id="カスタムメタデータカラムの作成" tabindex="-1">カスタムメタデータカラムの作成 <a class="header-anchor" href="#カスタムメタデータカラムの作成" aria-label="Permalink to “カスタムメタデータカラムの作成”">​</a></h2><p>一般的なスプレッドシートページにさらに情報を追加するには、カスタム<strong>メタデータカラム</strong>を作成する必要があります。</p><p>難易度レベル、<strong>天候</strong>、<strong>タグ</strong>など、ページに追加する追加情報があるかもしれません。 すべてのテキスト（または数値）情報をカスタムメタデータ列に保存することができます。</p><p>名前列の近くにある<strong>+</strong>をクリックします。</p><p><img src="'+dp+'" alt="メタデータ列"></p><p>タイプ**オプションでは、情報をどのように保存するかを選択できます。</p><ul><li>自由入力の<strong>テキスト</strong>、</li><li><strong>数値</strong>、</li><li><strong>チェックボックス</strong>、</li><li><strong>値のリスト</strong>、</li><li><strong>タグのリスト</strong>、</li><li><strong>チェックリスト</strong>。</li></ul><p><img src="'+Fp+'" alt="メタデータカラムの詳細"></p><p>::: 警告 テキスト、数値、およびチェックボックスでは、各エンティティに異なる情報を追加できます。最初に計画する必要はありません。</p><p>リスト値、タグリスト、およびチェックリストでは、各エンティティに同じ選択肢が与えられます。さらに、これは現在入力する必要があります。</p><p><img src="'+Tp+'" alt="メタデータカラムリスト"></p><p>利用可能な値<strong>の下にリスト要素を入力し、</strong>値を追加**をクリックして確認します。 :::</p><p>メタデータカラム<strong>を1つまたは複数の</strong>部門**にリンクすることもできます。</p><p>ヒント メタデータ列を部門にリンクします。アーティスト/スーパーバイザーは、自分のToDoページと部門フィルタリングビューでこれを見ることができます。</p><p>メタデータ列を1つまたは複数の部門にリンクすることができます。リストから部門をクリックし、<strong>追加</strong>をクリックして有効にします。</p><p>ここでは、VFX列が2つの部門にリンクされています。</p><p><img src="'+Np+'" alt="部門メタデータ列のフィルタリング表示"></p><p>:::</p><p>::: 詳細 メタデータ列の編集 アセットのグローバルページまたはNFTコレクションのグローバルページで、メタデータ列の右側にある矢印をクリックし、<strong>[編集]</strong>をクリックします。</p><p><img src="'+up+'" alt="メタデータ列の編集"> :::</p><p>この情報は、グローバルスプレッドシートページで直接入力できます。 ケースは編集可能です。</p><p><img src="'+fp+'" alt="メタデータ列の詳細"></p><p>::: ヒント 左側の複数のエンティティを選択してからメタデータ列を修正すると、メタデータ列を一括で修正できます。 :::</p><p>::: 詳細 手動で編集 編集ボタンを使用して情報を変更することもできます！<a href="../img/getting-started/edit_button.png">編集ボタン</a>。</p><p>編集ポップアップに新しい行が表示されます。リストから情報を選択することもできますし、 あるいは、テキストや数値を直接入力したり、チェックボックスにチェックを入れたり、チェックリストを使用したりすることもできます。</p><p>編集が完了したら、<strong>確認</strong>ボタンを押すことを忘れないでください。</p><p><img src="'+bp+'" alt="メタデータ列の詳細"> :::</p><p>メタデータ列の編集または削除が必要な場合は、スプレッドシートの一般ページに移動します。 メタデータ列の名前の近くにある矢印をクリックします <img src="'+kp+'" alt="メタデータ列の詳細">。</p><p>::: ヒント この新しい列を使用して、グローバルページを<strong>ソート</strong>することができます。列名の右側にある矢印をクリックして、このメニューを開きます。次に、「<strong>ソート</strong>」をクリックします。</p><p>また、メタデータ列を左側に<strong>固定</strong>することもできます。 :::</p><h2 id="ブレークダウンリストの作成" tabindex="-1">ブレークダウンリストの作成 <a class="header-anchor" href="#ブレークダウンリストの作成" aria-label="Permalink to “ブレークダウンリストの作成”">​</a></h2><p>ブレークダウンを記入すると、NFTコレクションの作成に役立ちます。 ブレークダウンには、NFTコレクションを作成するために追加する必要があるアセットの詳細がすべて記載されています。 これにより、必要なものをすべて漏れなく記載できるでしょう。</p><p>ドロップダウンメニューで <strong>BREAKDOWN</strong> を選択します。</p><p><img src="'+xp+'" alt="ドロップダウンメニューのブレイクダウン"></p><p>ブレイクダウンページの左側には、エピソード/シーケンス/NFTコレクションメニュー（1）があります。作成したものの中から選択できます。これらは画面の右側に表示され、 作成したすべての資産は、この制作（メインパックおよびエピソード）（3）で利用できます。さらに、 中央セクションでは、NFTコレクションの選択肢（2）があります。</p><p><img src="'+Kp+'" alt="ブレークダウンページ"></p><p>そこで、キャストしたいNFTコレクションを選択する必要があります。</p><p>サムネイルがまだない場合はテキストとしてアセットを表示したり、 サムネイルのサイズを拡大することもできます。</p><p><img src="'+Pp+'" alt="ブレークダウンページのテキスト表示"></p><p>また、ブレークダウン中にリストにアセットを追加する必要があることに気づくかもしれません。</p><p>ブレークダウンページから直接新しいアセットを作成できます。「利用可能なすべてのアセット」の右にある「+」をクリックします。</p><p><img src="'+Sp+'" alt="ブレークダウンページでアセットを作成"></p><p>複数のNFTコレクションを一度に選択することもできます。最初のNFTコレクションをクリックし、<strong>シフト</strong>キーを押したまま、選択する最後のNFTコレクションをクリックします。</p><p><img src="'+Cp+'" alt="ブレークダウンページでグローバル一括選択"></p><p>次に、割り当てたいアセットをクリックします。 キャラクター、背景など、右側（3）から選択します。 複数のNFTコレクションを選択した場合、選択したアセットは多数のNFTコレクションに適用されます。</p><p>アセットが入力されたNFTコレクションをコピーし、このアセット選択を別のNFTコレクションに貼り付けます。</p><p>アセットの上にカーソルを移動させると、<strong>+1</strong>または<strong>+10</strong>と表示されます。これは このアセットを追加した回数であり、必要なだけクリックできます。</p><p><img src="'+Vp+'" alt="Breakdown add asset"></p><p>シーケンスやNFTコレクションを指定せずに、すべてのアセットをテレビ番組のエピソードにリンクすることもできます。</p><p><img src="'+Ap+'" alt="Breakdown episode asset"></p><p>この方法では、絵コンテ/アニマティックの段階の前に、すべてのアセットを1つまたは複数のエピソードにリンクすることができます。</p><p>画面中央にアセットが表示されているのが確認できます（2）。 アセット名の隣には、追加された回数が表示されています。この 例では、キャラクターアセットのラマを2回追加しています。</p><p>誤ってアセットを2回追加してしまった場合は、画面中央部分に戻り、このNFTコレクションのアセットを選択します（2）。そこから、<strong>-1</strong>をクリックします。 このNFTコレクションを終えたら、他のNFTコレクションを続行します。 選択した内容は自動的に保存されます。</p><p><img src="'+vp+'" alt="ブレークダウンでアセットを削除"></p><p>ストーリーボードの作成中に新しいアセットが作成された場合は、アセットページに戻り （ドロップダウンメニューを使用）、必要なアセットを作成します。以前に作成したタスクは、これらの新しいアセットに即座に適用されます。 ただし、割り当てを行う必要があり、その後 ブレークダウンを続行できます。</p><p>これで、<strong>Breakdown</strong>ページは以下のようになります。</p><p><img src="'+t+'" alt="breakdown add asset bulk"></p><p>アセットを組み立てて個々のパーツを追跡する必要がある場合は、アセットのブレークダウンリストを作成することもできます。</p><p>画面左上にある<strong>FOR</strong>の下のドロップダウンメニューで<strong>asset</strong>を選択します。</p><p><img src="'+Dp+'" alt="アセットのブレークダウンメニュー"></p><p>2つ目のドロップダウンメニューにアクセスして、アセットの種類を選択できます。 <strong>キャラクター</strong>、<strong>環境</strong>、<strong>小道具</strong>、<strong>FX</strong>、...</p><p><img src="'+wp+'" alt="アセットタイプのブレークダウン"></p><p>アセットのブレークダウンページは、NFTコレクションと同じ方法で完了できます。まず、左側で1つまたは複数のアセットを選択し、次に右側の要素を追加します。</p><p>::: 詳細 CSVファイルからブレークダウンリストを作成する</p><p>すでにスプレッドシートファイルで内訳リストが準備できているかもしれません。Kitsuでは、それをインポートする方法が2つあります。1つ目は、.csvファイルを直接インポートする方法、2つ目は、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、Kitsuの推奨に従って、スプレッドシートを <code>.csv</code> ファイルとして保存します。</p><p>インポート] ボタンをクリックします！[インポート] ボタン (../img/getting-started/import.png)</p><p>「CSVからデータをインポート」というポップアップウィンドウが開きます。「参照」をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+e+'" alt="インポートしたCSVファイルの分割"></p><p>結果を確認するには、「プレビュー」ボタンをクリックします。</p><p>データのプレビューで、列の名前を確認し、調整することができます。</p><p>注意：<strong>[エピソード]</strong>の列は、<strong>[テレビ番組]</strong>制作の場合のみ必須です。</p><p><img src="'+r+'" alt="ブレークダウンインポートプレビュー"></p><p>すべてが適切であることを確認したら、<strong>[確認]</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、ブレークダウンがKitsuにインポートされました。</p><p><img src="'+t+'" alt="ブレークダウンインポートプレビュー"> :::</p><p>::: 詳細 スプレッドシートファイルをコピー＆ペーストしてブレークダウンリストを作成</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+Bp+'" alt="インポートコピーデータ"></p><p>次に、Kitsuのブレークダウンページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ「<strong>CSVからデータをインポート</strong>」が開きますので、「<strong>CSVデータを貼り付け</strong>」タブをクリックします。</p><p><img src="'+e+'" alt="インポートデータコピーペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong> ボタンで結果を確認できます。</p><p><img src="'+r+'" alt="データのコピー＆ペースト"></p><p>データのプレビューで列の名前を確認し、調整できます。</p><p>注：<strong>[エピソード]</strong> 列は、<strong>[テレビ番組]</strong> 制作の場合のみ必須です。</p><p><img src="'+r+'" alt="インポートデータのコピー＆ペースト"></p><p>すべてが正しく入力されたら、<strong>Confirm</strong>（確認）ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされました。</p><p><img src="'+t+'" alt="インポートデータのコピー＆ペースト"> :::</p><h2 id="アセットの状態の紹介-準備完了" tabindex="-1">アセットの状態の紹介：準備完了 <a class="header-anchor" href="#アセットの状態の紹介-準備完了" aria-label="Permalink to “アセットの状態の紹介：準備完了”">​</a></h2><p>ほとんどの場合、NFTコレクションのタスクでアセットを使用する際に、そのアセットのタスクが承認されるのを待つ必要はありません。</p><p>たとえば、アセットが <strong>コンセプト</strong> 段階で承認された場合、<strong>ストーリーボード</strong> 段階で使用することができます。 次に、<strong>モデリング</strong> 段階で承認された場合、<strong>レイアウト</strong> 段階で使用することができます。</p><p>アセットの状態 <strong>Ready For</strong> がまさに実行しているのは、アセットのタスクの状態を知らせ、NFTコレクションのタスクでの使用可能性を比較することです。</p><p>内訳を記入したので、どのアセットがすべてのNFTコレクションで使用されているかがわかります。</p><p>まず、タスクの状態に対するアセットの状態を定義する必要があります。セルをクリックして<strong>準備完了</strong>を変更できます。NFTコレクションのタスクを含むドロップダウンメニューが表示されます。</p><p><img src="'+Ip+'" alt="アセットの状態"></p><p>::: ヒント <strong>自動化</strong>機能を使用して、作業を自動化することができます。</p><p><strong>準備完了</strong>のトリガーで自動化を設定できます。 :::</p><p>いくつかのアセットの状態を<strong>準備完了</strong>に変更したので、NFTコレクションページで結果を確認できます。</p><p>いくつかの白いボックスが<strong>緑色</strong>になっていることに気づくでしょう。このNFTコレクションに含まれるすべてのアセットが、この特定のタスクの準備ができていることを示しています。</p><p><img src="'+yp+'" alt="Asset Status"></p><p>白いボックスが表示されている場合、Kitsuは、このタスクに準備ができているアセットの数を示します。</p><p><img src="'+Rp+'" alt="Asset Status"></p><p>::: ヒント ボックスが表示されていない場合、このNFTコレクションにアセットがキャストされていません。 :::</p><p>次に、NFTコレクションの名前をクリックして詳細ページに移動します。 すると、このNFTコレクションにキャストされたすべてのアセットとそのステータスが表示されます。</p><p><img src="'+Ep+'" alt="アセットステータス"></p><p>特定のタスクに対してNFTコレクションを開始できるかどうかを判断する最も簡単な方法です。</p>',381)])])}const Xp=m(Hp,[["render",Op]]);export{Mp as __pageData,Xp as default};
